import { Field as FieldPrimitive } from '@base-ui/react/field';
import { mergeProps } from '@base-ui/react/merge-props';
import { forwardRef, useCallback, type ComponentProps, type ForwardedRef } from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Textarea.module.css';

type TextareaProps = Omit<ComponentProps<'textarea'>, 'onChange'> & {
  autoResize?: boolean;
  onValueChange?: (value: string) => void;
};

const assignForwardedRef = <T,>(ref: ForwardedRef<T>, value: T | null) => {
  if (typeof ref === 'function') {
    ref(value);
    return;
  }

  if (ref) {
    ref.current = value;
  }
};

const Textarea = forwardRef<HTMLTextAreaElement, TextareaProps>(function Textarea(
  { autoResize = false, className, onValueChange, ...props }: TextareaProps,
  forwardedRef: ForwardedRef<HTMLTextAreaElement>,
) {
  const setTextareaRef = useCallback(
    (node: HTMLElement | null) => {
      assignForwardedRef(forwardedRef, node instanceof HTMLTextAreaElement ? node : null);
    },
    [forwardedRef],
  );

  return (
    <FieldPrimitive.Control
      ref={setTextareaRef}
      data-slot="textarea-root"
      data-auto-resize={autoResize ? '' : undefined}
      className={mergeClassName(className, styles.root)}
      render={(controlProps) => (
        <textarea
          {...mergeProps(controlProps, props, {
            onChange: (event) => {
              onValueChange?.(event.currentTarget.value);
            },
          })}
        />
      )}
    />
  );
});

export { Textarea };
export type { TextareaProps };

@layer ui.components {
  .root {
    box-sizing: border-box;
    width: var(--textarea-width, 100%);
    max-width: var(--textarea-max-width, none);
    min-height: var(--textarea-min-height, 6rem);
    margin: 0;
    border: var(--textarea-border-width, var(--border-width-sm)) var(--textarea-border-style, solid)
      var(--textarea-border-color, var(--color-border));
    border-radius: var(--textarea-radius, var(--radius-md));
    padding: var(--textarea-padding-y, 0.5rem) var(--textarea-padding-x, 0.875rem);
    background-color: var(--textarea-bg, var(--color-background));
    color: var(--textarea-color, var(--color-foreground));
    font: inherit;
    font-size: var(--textarea-font-size, var(--text-md));
    line-height: var(--textarea-line-height, var(--line-height-text-md));
    outline: var(--textarea-focus-ring-width, var(--textarea-border-width, var(--border-width-sm)))
      solid transparent;
    outline-offset: var(
      --textarea-focus-ring-offset,
      calc(0px - var(--textarea-border-width, var(--border-width-sm)))
    );
    resize: var(--textarea-resize, vertical);
    transition:
      border-color var(--textarea-transition, var(--transition-default)),
      outline-color var(--textarea-transition, var(--transition-default)),
      opacity var(--textarea-transition, var(--transition-default));
  }

  .root::placeholder {
    color: var(--textarea-placeholder-color, var(--color-muted-foreground));
  }

  .root:focus-visible {
    outline-color: var(--textarea-focus-ring-color, var(--color-ring));
  }

  .root[data-invalid] {
    border-color: var(--textarea-border-color-invalid, var(--color-destructive));
  }

  .root[data-invalid]:focus-visible {
    outline-color: var(--textarea-border-color-invalid, var(--color-destructive));
  }

  .root:is([disabled], [data-disabled]) {
    pointer-events: none;
    opacity: var(--textarea-disabled-opacity, var(--opacity-disabled));
  }

  .root:is(:read-only, [data-readonly]) {
    background-color: var(--textarea-readonly-bg, var(--textarea-bg, var(--color-background)));
    color: var(--textarea-readonly-color, var(--textarea-color, var(--color-foreground)));
  }

  @supports (field-sizing: content) {
    .root[data-auto-resize] {
      field-sizing: content;
      overflow-y: hidden;
      resize: none;
    }
  }
}
